#!/usr/bin/env python3
import requests, base64, os, sys

TOKEN = input("GitHub Token: ").strip()
REPO  = "intelligentresponder-max/telavendelele"
API   = "https://api.github.com/repos/" + REPO
HDR   = {"Authorization": "token " + TOKEN, "Accept": "application/vnd.github+json"}

def upload(pfad, b64, msg):
    print("Lade hoch:", pfad)
    sha = None
    ex = requests.get(API + "/contents/" + pfad, headers=HDR)
    if ex.status_code == 200:
        sha = ex.json().get("sha")
    payload = {"message": msg, "content": b64}
    if sha: payload["sha"] = sha
    r = requests.put(API + "/contents/" + pfad, headers=HDR, json=payload)
    print("OK" if r.status_code in (200,201) else "FEHLER " + str(r.status_code))

print("Aktiviere GitHub Pages...")
r = requests.put(API + "/pages", headers=HDR, json={"source":{"branch":"master","path":"/"}})
if r.status_code in (200,201):
    print("Pages live:", r.json().get("html_url",""))
elif r.status_code == 409:
    r2 = requests.get(API + "/pages", headers=HDR)
    print("Pages bereits aktiv:", r2.json().get("html_url",""))
else:
    print("Pages Fehler:", r.status_code)

AGENT = ""
CFG   = ""
REQS  = "cmVxdWVzdHM+PTIuMzEuMApQeVlBTUw+PTYuMC4xCg=="

upload("src/haendler_agent.py", AGENT, "Neuer Haendler-Agent Overpass API")
upload("config.yaml",           CFG,   "config.yaml Frankfurt Rhein-Main")
upload("requirements.txt",      REQS,  "requirements.txt bereinigt")

print("")
print("Fertig! Live in 1-2 Min:")
print("https://intelligentresponder-max.github.io/telavendelele/")
